// FormatDate.js

export const formatFullDateMonthYear = (dateString) => {
  const date = new Date(dateString);
  const options = {
    year: "numeric",
    month: "long",
    day: "numeric",
  };
  return date.toLocaleDateString("en-US", options);
};

export const formatDateShortMonthYear = (dateString) => {
  const date = new Date(dateString);
  const options = {
    year: "numeric",
    month: "short",
    day: "numeric",
  };
  return date.toLocaleDateString("en-US", options);
};

export const formatMonthYear = (dateString) => {
  const date = new Date(dateString);
  const options = {
    year: "numeric",
    month: "short",
  };
  return date.toLocaleDateString("en-US", options);
};

