import React from "react";
import { Link, graphql } from "gatsby";
import { GatsbyImage, getImage } from "gatsby-plugin-image";
import { LayoutProse } from "src/components/layouts/layout";
import { SeoDefault } from "src/components/Seo";
import { KeywordsFilter } from "src/utils/KeywordsFilter";
import { CardFrontmatter } from "src/templates/frontmatter/CardFrontmatter";
import { formatDateShortMonthYear } from "src/utils/FormatDate";
import { toTitleCase } from "src/utils/toTitleCase";
import PlaceholderImage from "src/assets/placeholder/2000x2000.png";

const keywordsKey = "keywords";
const pType = "archive";
const capPType = toTitleCase(pType);
const isValidTitle = (title) => {
  return title && title !== "placeholder" && title !== "Placeholder";
};

const ArchivePage = ({ data }) => {
  const { filteredNodes } = KeywordsFilter(data.allMdx.nodes, keywordsKey);

  const validNodes = filteredNodes.filter((node) =>
    isValidTitle(node.frontmatter.title),
  );
  return (
    <LayoutProse pageTitle={capPType}>
      <main className="pg-cd-card-wrp-lview">
        {validNodes.map((node) => {
          const image = getImage(node.frontmatter.hero_img_src);

          return (
            <article key={node.id} className="pg-cd-gd-lview pg-cd-bsc-lview">
              {/* Date */}
              <p
                title={formatDateShortMonthYear(node.frontmatter.date)}
                className="pg-cd-date-lview"
              >
                {formatDateShortMonthYear(node.frontmatter.date)}
              </p>

              {/* Hero image */}
              <div className="pg-cd-img-wrp-lview">
                <Link
                  to={`/${node.frontmatter.p_type}/${node.frontmatter.slug}`}
                >
                  {node.frontmatter.hero_img_src ? (
                    <GatsbyImage
                      title={node.frontmatter.title}
                      image={image}
                      alt={
                        node.frontmatter.hero_img_alt
                          ? node.frontmatter.hero_img_alt
                          : node.frontmatter.title
                      }
                      className="g-card-img"
                    />
                  ) : (
                    <img
                      alt="Placeholder"
                      src={PlaceholderImage}
                      title={node.frontmatter.title}
                      className="g-card-img"
                    />
                  )}
                </Link>
              </div>

              {/* Title */}
              <div className="pg-cd-tit-lview">
                <Link
                  title={node.frontmatter.title}
                  to={`/${node.frontmatter.p_type}/${node.frontmatter.slug}`}
                  className="g-hidden-link"
                >
                  {node.frontmatter.title}
                </Link>
              </div>

              {/* CardFrontmatter & ReadMoreLink */}
              <CardFrontmatter
                node={node}
                keywordsKey={keywordsKey}
                extraClass="card-fm-ec"
                customOrder
              />
            </article>
          );
        })}
      </main>
    </LayoutProse>
  );
};

export const query = graphql`
  query ArchiveQuery {
    allMdx(
      sort: { frontmatter: { date: DESC } }
      filter: { frontmatter: { slug: {}, p_type: { eq: "archive" } } }
    ) {
      nodes {
        frontmatter {
          title
          title_sub
          slug
          p_type
          date
          keywords {
            id
            name
          }
          hero_img_alt
          hero_img_src {
            childImageSharp {
              gatsbyImageData
            }
          }
        }
        id
        excerpt(pruneLength: 150)
      }
    }
  }
`;

export default ArchivePage;

export const Head = () => <SeoDefault title={toTitleCase(pType)} />;
