// CardFrontmatter.js

import React, { useState } from "react";
import { ReadMoreLink } from "src/utils/ReadMoreLinks";
import { KeywordButtonsGeneral } from "src/utils/KeywordButtons";
import { ShowMoreButton } from "src/utils/ShowMoreButton";
import { PubFrontmatter } from "src/templates/frontmatter/PubFrontmatter";

const P_TYPE_CONFIG = {
  projects: { showAbstract: false, showExcerpt: false },
  pub: { showAbstract: true, showExcerpt: false },
  news: { showAbstract: false, showExcerpt: true },
  blog: { showAbstract: false, showExcerpt: true },
  models: { showAbstract: false, showExcerpt: true },
};

export const CardFrontmatter = ({
  node,
  keywordsKey,
  customOrder = false,
  extraClass,
  readMoreExtraClass,
  keywordExtraClass,
  // extraClass = "",
  // readMoreExtraClass = "",
  // keywordExtraClass = "",
}) => {
  const { p_type } = node.frontmatter;
  const { showAbstract, showExcerpt } = P_TYPE_CONFIG[p_type] || {};

  const [isExpanded, setIsExpanded] = useState(false);

  const toggleExpand = () => {
    setIsExpanded(!isExpanded);
  };

  const renderAbstract = () => {
    const words = node.frontmatter.abstract.split(" ");
    if (p_type === "pub" && words.length > 50 && !isExpanded) {
      return words.slice(0, 50).join(" ") + " ...";
    }
    return node.frontmatter.abstract;
  };

  return (
    <div className={`card-fm-wrp${extraClass ? ` ${extraClass}` : ""}`}>
      {/* Conditional rendering for p_type 'pub' */}
      {p_type === "pub " && <PubFrontmatter p_type="pub" node={node} />}

      {/* Content */}
      {(showAbstract && node.frontmatter.abstract) ||
      (showExcerpt && node.excerpt) ? (
        <p className="card-fm-txt">
          {showAbstract ? renderAbstract() : node.excerpt}
          {showAbstract && node.frontmatter.abstract.split(" ").length > 50 && (
            <>
              <ShowMoreButton
                isExpanded={isExpanded}
                toggleExpand={toggleExpand}
              />
            </>
          )}
        </p>
      ) : null}

      {/* ReadMoreLink component */}
      {(showAbstract || showExcerpt) && (
        <div className={`g-rml-wrp ${customOrder ? "order-3" : "order-2"}`}>
          <ReadMoreLink
            slug={node.frontmatter.slug}
            pType={p_type}
            extraClass={readMoreExtraClass && readMoreExtraClass}
          />
        </div>
      )}
      {/* Keywords */}
      <div className={customOrder ? "order-2" : "order-3"}>
        <KeywordButtonsGeneral
          keywords={node.frontmatter[keywordsKey]}
          extraClass={keywordExtraClass && keywordExtraClass}
        />
      </div>
    </div>
  );
};
